// Returns spread structure, theoretical premium, and sizing for one setup.
// Uses ATR-derived IV (ATR/price × √252) — leans slightly high because ATR
// includes overnight gaps. Treat output as an upper-bound estimate.
function computeOptionsLayer(r) {
  const { entry, target2R, atr14, direction, riskDollars } = r;
  if (entry == null || target2R == null || !atr14) return null;
  const isCall = direction === 'LONG';
  const sigma  = Math.min(2.0, (atr14 / entry) * Math.sqrt(252));
  const T      = 6.42 / (6.5 * 252); // 9:35 AM → 4:00 PM ET as fraction of trading year
  const inc    = strikeIncrement(entry);
  const longK  = nearestStrike(entry);
  let shortK   = isCall
    ? Math.ceil(target2R  / inc) * inc
    : Math.floor(target2R / inc) * inc;
  if (isCall  && shortK <= longK) shortK = longK + inc;
  if (!isCall && shortK >= longK) shortK = longK - inc;
  const longPrem  = bsmPrice(entry, longK,  T, 0.05, sigma, isCall);
  const shortPrem = bsmPrice(entry, shortK, T, 0.05, sigma, isCall);
  const netDebit  = Math.max(0.01, longPrem - shortPrem);
  const width     = Math.abs(shortK - longK);
  const maxProfit = width - netDebit;
  if (maxProfit <= 0) return null;
  const contracts = Math.max(1, Math.floor((riskDollars ?? 0) / (netDebit * 100)));
  const breakEven = isCall ? longK + netDebit : longK - netDebit;
  return {
    isCall, longK, shortK, width,
    netDebit, maxProfit,
    rrRatio:   maxProfit / netDebit,
    contracts,
    totalCost:      contracts * netDebit * 100,
    totalMaxProfit: contracts * maxProfit * 100,
    breakEven,
    movePct: ((breakEven - entry) / entry) * 100,
    iv:      sigma,
  };
}

